import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(coord1, coord2):
        return np.linalg.norm(coord1 - coord2)

    # Calculate travel time to each unvisited customer from current position
    travel_times = [distance(cur_truck_pos, unvisited_customers[i]) / truck_speed for i in range(len(unvisited_customers))]

    # Calculate the urgency based on time window and current time, penalizing more for being likely to miss the window
    urgency_scores = []
    for i, time_window in enumerate(time_windows):
        start_time, end_time = time_window 
        arrival_time = current_time + travel_times[i]
        if arrival_time < start_time:
            # Calculate waiting time if arrived early
            urgency_scores.append((start_time - current_time) / truck_speed + 0.1 * (end_time - start_time))
        elif arrival_time > end_time:
            # Heavy penalty if we're going to miss the window
            urgency_scores.append(1000 + arrival_time - end_time)
        else:
            # If within time window, prefer sooner times
            urgency_scores.append(travel_times[i])

    # Select the customer with the lowest urgency score
    best_node = np.argmin(urgency_scores)

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def compute_travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    best_node = None
    min_penalty_time = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = compute_travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        start_time, end_time = time_windows[i]

        if arrival_time < start_time:
            penalty_time = start_time - arrival_time  # Positive means waiting time
        elif arrival_time > end_time:
            penalty_time = (arrival_time - end_time) * 10  # Higher penalty if missing time window
        else:
            penalty_time = 0  # No penalty if within time window

        # Adjusted with heuristic: minimizing penalty, prefer closer deadlines if penalties are same
        adjusted_penalty_time = penalty_time + (end_time - current_time) / 1000

        if adjusted_penalty_time < min_penalty_time:
            min_penalty_time = adjusted_penalty_time
            best_node = i

    # If no viable option found, the truck will wait at the current position
    if best_node is None:
        return None

    return best_node
